import { isNumber, isString, isUndefined } from 'lodash-es';
import { type ReactNode } from 'react';

import { _sanitizeSymbol as sanitizeSymbol } from '../../../../../core/utils/sanitize-symbol.js';
import { AnnotationsMarkerConfig } from '../types/annotations-marker-props.js';

export const defineMarkerContent = (markers: AnnotationsMarkerConfig[]) => {
  let markerContent: ReactNode;

  if (markers.length > 1) {
    markerContent = markers.length.toString();
  } else {
    const marker = markers[0];
    const { symbol, title } = marker;

    if (!isUndefined(symbol)) {
      if (isString(symbol) || isNumber(symbol)) {
        markerContent = sanitizeSymbol(`${symbol}`);
      } else {
        markerContent = symbol;
      }
    } else {
      markerContent = title ?? '';
    }
  }

  return markerContent;
};
